#include <iostream>
#include <algorithm>
using namespace std;
int main()
{
    int n,count=0;
    long long a[1000005];
    cin>>n;
    for(int i=0;i<=n-1;i++)
    {
        cin>>a[i];
    }
    sort(a,a+n);
    int tian=0;
    for(int i=0;i<=n-1;i++)
    {
        tian++;
        while(a[i]<=tian)
        {
            i++;
            if(i==n-1)
            {
                break;
            }
        }
    }
    cout<<tian+1;
    return 0;
}
